        return None, "User doesn't exist with this email"
    # Verify the password
    isMatched = verifyPwd(userdata.password, str(exist.hashed_pwd))
    if not isMatched:
        return None, "Invalid credentials"
    return exist, None

def upload_image(file: UploadFile, type: str, type_id: str):
    upload = cloudinary.uploader.upload(
        file.file, folder=f"{type}/{type_id}", public_id=f"{type}", overwrite=True
    )
    return upload["secure_url"]
